mapper.select:
SELECT COUNT(*) AS TOTAL FROM TBL_PROD_WORKORDER

    AND ORDDATE >= #{start_date}
    AND ORDDATE <= #{end_date}
    AND PLANTCD = #{plant_cd}
    AND SHIFT = #{shift}
    AND ORDSTATE = #{ord_state}

        AND (PAR_WORKORDNO IS NULL OR PAR_WORKORDNO = '')


        AND (WORKORDNO LIKE #{search} OR PARTNO LIKE #{search} OR PAR_WORKORDNO LIKE #{search})

    AND USEYN = 1

SELECT W.*, G.PARTNM, G.STANDARD, G.UNIT, P.PROCESSNM, L.LINENM
FROM TBL_PROD_WORKORDER W
LEFT JOIN TBL_COM_GOODS G ON W.PARTNO = G.PARTNO
LEFT JOIN TBL_COM_PROCESS P ON W.PROCESSCD = P.PROCESSCD
LEFT JOIN TBL_COM_LINE L ON W.LINECD = L.LINECD

    AND W.ORDDATE >= #{start_date}
    AND W.ORDDATE <= #{end_date}
    AND W.PLANTCD = #{plant_cd}
    AND W.SHIFT = #{shift}
    AND W.ORDSTATE = #{ord_state}

        AND (W.PAR_WORKORDNO IS NULL OR LTRIM(RTRIM(W.PAR_WORKORDNO)) = '')


        AND (W.WORKORDNO LIKE #{search} OR W.PARTNO LIKE #{search} OR G.PARTNM LIKE #{search} OR W.PAR_WORKORDNO LIKE #{search})

    AND W.USEYN = 1

ORDER BY W.ORDDATE DESC, W.WORKORDNO DESC

OFFSET #{offset} ROWS FETCH NEXT #{limit} ROWS ONLY

mapper.update:
UPDATE TBL_PROD_WORKORDER
PROCESSCD = #{PROCESSCD}, SHIFT = #{SHIFT}, ORDQTY = #{ORDQTY}, ORDTYPE = #{ORDTYPE}, ORDpriority = #{ORDpriority}, ORDSTATE = #{ORDSTATE}, LINECD = #{LINECD}, REMARK = #{REMARK}, EDITUSERID = #{EDITUSERID}, EDITDTM = GETDATE()
WHERE WORKORDNO = #{WORKORDNO}

mapper.delete:
UPDATE TBL_PROD_WORKORDER 
SET USEYN = 0, EDITUSERID = #{EDITUSERID}, EDITDTM = GETDATE()
WHERE WORKORDNO = #{WORKORDNO}
